const timeout = new Promise((_, reject) =>
  setTimeout(() => reject(new Error('timeout')), 3000),
);
const data = await Promise.race([fetch('/api'), timeout]);

Dim tasks = New Task() { Task.Run(Sub() FetchData()), Task.Delay(3000) }
Dim completedTask = Task.WaitAny(tasks)
If completedTask = 1 Then Debug.Print "timeout in race"

ExecutorService exec = Executors.newFixedThreadPool(2);
Future<String> f1 = exec.submit(() -> fetchData());
Future<String> f2 = exec.submit(() -> { Thread.sleep(3000); throw new TimeoutException("race"); });
String winner = CompletableFuture.anyOf(f1, f2).get().toString();

SELECT FIRST(CASE WHEN status = 'done' THEN result END) AS race_result
FROM race_events
ORDER BY timestamp ASC;
